import{_ as t,c as e,o,a1 as l}from"./chunks/framework.DDNAyvCW.js";const i="/assets/mobile_asset._NB4u5ra.jpg",b=JSON.parse('{"title":"资产管理","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/assets/index.md","filePath":"docs/mobile/assets/index.md"}'),d={name:"docs/mobile/assets/index.md"};function r(s,a,c,n,h,u){return o(),e("div",null,a[0]||(a[0]=[l('<h1 id="资产管理" tabindex="-1">资产管理 <a class="header-anchor" href="#资产管理" aria-label="Permalink to &quot;资产管理&quot;">​</a></h1><p>资产模块是移动端管理 SSH 资源的入口，包含直接连接、堡垒机资源和密钥管理。</p><div style="text-align:center;"><img src="'+i+'" alt="Asset management" width="320"></div><h2 id="直接连接" tabindex="-1">直接连接 <a class="header-anchor" href="#直接连接" aria-label="Permalink to &quot;直接连接&quot;">​</a></h2><p>直接连接用于管理个人添加的服务器资产。</p><h3 id="添加新资产" tabindex="-1">添加新资产 <a class="header-anchor" href="#添加新资产" aria-label="Permalink to &quot;添加新资产&quot;">​</a></h3><p>点击右下角 <code>+</code> → <strong>新建</strong>，填写服务器信息后保存。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>标签</td><td>便于识别的名称，如 <code>prod-web-01</code></td></tr><tr><td>IP / 域名</td><td>服务器地址</td></tr><tr><td>端口</td><td>默认 <code>22</code></td></tr><tr><td>用户名</td><td>登录用户，如 <code>root</code>、<code>ubuntu</code></td></tr><tr><td>认证方式</td><td><strong>密码</strong>：直接输入；<strong>密钥</strong>：需提前在<a href="#密钥管理">密钥管理</a>中导入</td></tr></tbody></table><h3 id="管理资产" tabindex="-1">管理资产 <a class="header-anchor" href="#管理资产" aria-label="Permalink to &quot;管理资产&quot;">​</a></h3><ul><li>连接：点击主机卡片即可建立 SSH 连接</li><li>编辑：长按卡片后选择 <code>编辑</code></li><li>收藏：长按卡片后选择 <code>收藏</code>，收藏项会置顶显示</li><li>删除：长按卡片后选择 <code>删除</code></li></ul><h3 id="最近连接排序" tabindex="-1">最近连接排序 <a class="header-anchor" href="#最近连接排序" aria-label="Permalink to &quot;最近连接排序&quot;">​</a></h3><p>主机列表按最后连接时间自动排序，最近使用过的主机优先显示在列表顶部，方便快速找到常用服务器。</p><h3 id="搜索与筛选" tabindex="-1">搜索与筛选 <a class="header-anchor" href="#搜索与筛选" aria-label="Permalink to &quot;搜索与筛选&quot;">​</a></h3><p>支持按以下字段搜索或过滤：</p><ul><li>主机名</li><li>IP 地址</li><li>用户名</li><li>分组</li></ul><h2 id="堡垒机资源" tabindex="-1">堡垒机资源 <a class="header-anchor" href="#堡垒机资源" aria-label="Permalink to &quot;堡垒机资源&quot;">​</a></h2><p>堡垒机资源用于管理通过跳板机维护的服务器资产。</p><h3 id="添加堡垒机" tabindex="-1">添加堡垒机 <a class="header-anchor" href="#添加堡垒机" aria-label="Permalink to &quot;添加堡垒机&quot;">​</a></h3><p>点击 <code>+</code> → <strong>新建</strong>，填写堡垒机名称、地址、端口和用户名，选择密钥认证后点击<strong>保存并同步</strong>。</p><p>保存后，同步的服务器资产会显示在堡垒机的下拉列表中。</p><h3 id="管理堡垒机" tabindex="-1">管理堡垒机 <a class="header-anchor" href="#管理堡垒机" aria-label="Permalink to &quot;管理堡垒机&quot;">​</a></h3><ul><li>同步资产：点击分组标题旁的同步按钮</li><li>编辑：长按分组名称后选择 <code>编辑</code></li><li>删除：长按分组名称后选择 <code>删除</code></li></ul><h3 id="管理同步的服务器资产" tabindex="-1">管理同步的服务器资产 <a class="header-anchor" href="#管理同步的服务器资产" aria-label="Permalink to &quot;管理同步的服务器资产&quot;">​</a></h3><p>堡垒机下同步的资产支持以下操作：</p><ul><li>点击卡片建立连接</li><li>长按卡片编辑备注</li><li>长按卡片加入收藏</li></ul><h2 id="密钥管理" tabindex="-1">密钥管理 <a class="header-anchor" href="#密钥管理" aria-label="Permalink to &quot;密钥管理&quot;">​</a></h2><p>密钥管理用于维护 SSH 登录所需的密钥文件。</p><ul><li>点击右下角 <code>+</code> 按钮添加新密钥</li><li>支持从本地导入密钥文件</li><li>每个密钥卡片上提供编辑和删除操作</li></ul><div class="tip custom-block"><p class="custom-block-title">建议</p><p>如果主机较多，优先维护好收藏、分组和备注信息，检索效率会更高。</p></div>',29)]))}const m=t(d,[["render",r]]);export{b as __pageData,m as default};
